import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine(); // Read the whole line

        // Validate input length before copying to buffer
        if (userInput.length() > 10) {
            System.out.println("Input length exceeds buffer size. Please enter a shorter string.");
            return;
        }

        char[] buffer = new char[10];

        userInput.getChars(0, Math.min(userInput.length(), 10), buffer, 0); // Copy up to 10 characters

        System.out.println("Buffer contents: " + String.valueOf(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
